import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface Animal {
  id: number;
  identificador_unico: string;
  nombre: string;
  sexo: string;
  categoria: string;
  estado: string;
  raza_nombre: string;
  ubicacion_nombre: string;
  fecha_nacimiento: string;
}

const Animals: React.FC = () => {
  const [animals, setAnimals] = useState<Animal[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);

  useEffect(() => {
    loadAnimals();
  }, []);

  const loadAnimals = async () => {
    try {
      const response = await api.get('/animals');
      setAnimals(response.data);
    } catch (error) {
      console.error('Error cargando animales:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return (
    <div className="page-inner">
      <div className="card">
        <div style={{ padding: '40px', textAlign: 'center' }}>
          <i className="fas fa-spinner fa-spin" style={{ fontSize: '24px', color: '#1572e8' }}></i>
          <p style={{ marginTop: '10px', color: '#6c757d' }}>Cargando animales...</p>
        </div>
      </div>
    </div>
  );

  return (
    <div className="page-inner">
      <div className="card">
        <div className="card-header">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <h4 className="card-title">
              <i className="fas fa-paw" style={{ marginRight: '10px' }}></i>
              Gestión de Animales ({animals.length})
            </h4>
            <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
              <i className={`fas ${showForm ? 'fa-times' : 'fa-plus'}`} style={{ marginRight: '8px' }}></i>
              {showForm ? 'Cancelar' : 'Nuevo Animal'}
            </button>
          </div>
        </div>

        <div style={{ padding: '25px' }}>
          {/* Stats */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px', marginBottom: '25px' }}>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#1572e8' }}>{animals.length}</div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>TOTAL ANIMALES</div>
            </div>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#31ce36' }}>
                {animals.filter(a => a.estado === 'activo').length}
              </div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>ACTIVOS</div>
            </div>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#ffad46' }}>
                {animals.filter(a => a.categoria === 'reproductor').length}
              </div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>REPRODUCTORES</div>
            </div>
          </div>

          {/* Table */}
          <div className="table-responsive">
            <table className="table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Nombre</th>
                  <th>Sexo</th>
                  <th>Categoría</th>
                  <th>Estado</th>
                  <th>Raza</th>
                  <th>Ubicación</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {animals.map(animal => (
                  <tr key={animal.id}>
                    <td style={{ fontWeight: '600' }}>{animal.identificador_unico}</td>
                    <td>{animal.nombre || '-'}</td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        fontSize: '12px',
                        fontWeight: '600',
                        background: animal.sexo === 'hembra' ? '#f25961' : '#1572e8',
                        color: '#ffffff'
                      }}>
                        {animal.sexo === 'hembra' ? 'Hembra' : 'Macho'}
                      </span>
                    </td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        fontSize: '12px',
                        fontWeight: '600',
                        background: '#6c757d',
                        color: '#ffffff',
                        textTransform: 'capitalize'
                      }}>
                        {animal.categoria}
                      </span>
                    </td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        fontSize: '12px',
                        fontWeight: '600',
                        background: animal.estado === 'activo' ? '#31ce36' : 
                                   animal.estado === 'vendido' ? '#ffad46' : '#f25961',
                        color: '#ffffff',
                        textTransform: 'capitalize'
                      }}>
                        {animal.estado}
                      </span>
                    </td>
                    <td>{animal.raza_nombre || '-'}</td>
                    <td>{animal.ubicacion_nombre || '-'}</td>
                    <td>
                      <div style={{ display: 'flex', gap: '5px' }}>
                        <button className="btn btn-primary btn-sm" title="Ver">
                          <i className="fas fa-eye"></i>
                        </button>
                        <button className="btn btn-warning btn-sm" title="Editar">
                          <i className="fas fa-edit"></i>
                        </button>
                        <button className="btn btn-danger btn-sm" title="Eliminar">
                          <i className="fas fa-trash"></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {animals.length === 0 && (
            <div style={{ textAlign: 'center', padding: '40px', color: '#6c757d' }}>
              <i className="fas fa-paw" style={{ fontSize: '48px', marginBottom: '15px', opacity: 0.5 }}></i>
              <h5>No hay animales registrados</h5>
              <p>Comienza registrando tu primer animal</p>
              <button className="btn btn-primary" onClick={() => setShowForm(true)}>
                <i className="fas fa-plus" style={{ marginRight: '8px' }}></i>
                Registrar Animal
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Animals;
